// Generated by OrchestKit Claude Plugin
// Created: 2026-06-27

// Guards the orank "REST deprecation/versioning policy" recovery: the OpenAPI
// info.description must declare the API versioning scheme and the RFC 8594
// Deprecation/Sunset policy, and the shared `deprecationHeaders` helper must
// emit well-formed RFC 8594 headers when an endpoint is eventually retired.
// Nothing is deprecated today — this only asserts the policy + mechanism exist.

import { describe, expect, it } from "vitest";
import { buildOpenApiSpec } from "@/lib/openapi/spec";
import { deprecationHeaders } from "@/lib/problem";

describe("OpenAPI info.description declares versioning + deprecation policy", () => {
	const description = buildOpenApiSpec().info.description;

	it("declares path-based API versioning (/api/vN)", () => {
		expect(description).toMatch(/version/i);
		expect(description).toContain("/api/v1");
		expect(description).toMatch(/\/api\/vN/);
	});

	it("declares the RFC 8594 Deprecation + Sunset header policy", () => {
		expect(description).toMatch(/deprecat/i);
		expect(description).toContain("Deprecation");
		expect(description).toContain("Sunset");
	});
});

describe("deprecationHeaders helper (RFC 8594)", () => {
	it("emits an IMF-fixdate Deprecation header", () => {
		const headers = deprecationHeaders({ deprecation: new Date("2026-01-01T00:00:00Z") });
		expect(headers.Deprecation).toBe("Thu, 01 Jan 2026 00:00:00 GMT");
		expect(headers.Sunset).toBeUndefined();
		expect(headers.Link).toBeUndefined();
	});

	it("adds Sunset and a rel=deprecation Link when provided", () => {
		const headers = deprecationHeaders({
			deprecation: new Date("2026-01-01T00:00:00Z"),
			sunset: new Date("2026-07-01T00:00:00Z"),
			migrationDocsUrl: "https://orchestkit.yonyon.ai/api-policy.md",
		});
		expect(headers.Sunset).toBe("Wed, 01 Jul 2026 00:00:00 GMT");
		expect(headers.Link).toBe(
			'<https://orchestkit.yonyon.ai/api-policy.md>; rel="deprecation"; type="text/html"',
		);
	});
});
